package com.hospital.management.model;
import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.Objects;
/** Safe doctor profile joined with its application user and department. */
public class Doctor{private Long doctorId,userId,departmentId;private String departmentName,registrationNumber,firstName,lastName,specialization,qualification,phone,status,username,email,userStatus;private BigDecimal consultationFee;private LocalDateTime createdAt,updatedAt;
 public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public Long getUserId(){return userId;}public void setUserId(Long v){userId=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public String getRegistrationNumber(){return registrationNumber;}public void setRegistrationNumber(String v){registrationNumber=v;}public String getFirstName(){return firstName;}public void setFirstName(String v){firstName=v;}public String getLastName(){return lastName;}public void setLastName(String v){lastName=v;}public String getSpecialization(){return specialization;}public void setSpecialization(String v){specialization=v;}public String getQualification(){return qualification;}public void setQualification(String v){qualification=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public BigDecimal getConsultationFee(){return consultationFee;}public void setConsultationFee(BigDecimal v){consultationFee=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public String getUsername(){return username;}public void setUsername(String v){username=v;}public String getEmail(){return email;}public void setEmail(String v){email=v;}public String getUserStatus(){return userStatus;}public void setUserStatus(String v){userStatus=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public String getFullName(){return(firstName+" "+lastName).trim();}public boolean equals(Object o){return this==o||(o instanceof Doctor d&&doctorId!=null&&doctorId.equals(d.doctorId));}public int hashCode(){return Objects.hashCode(doctorId);}public String toString(){return"Doctor{id="+doctorId+", name='"+getFullName()+"', registration='"+registrationNumber+"'}";}}
